<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Sandbox</title>
    <style>
        :root {
            --bg-color: #121212;
            --panel-color: #1e1e1e;
            --text-color: #e0e0e0;
            --accent-color: #bb86fc;
            --sand-color: #f4d03f;
            --water-color: #3498db;
            --wall-color: #7f8c8d;
            --acid-color: #2ecc71;
            --empty-color: #2c3e50;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
            margin: 0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            overflow: hidden;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
            padding: 20px;
            background: var(--panel-color);
            border-radius: 16px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
        }

        #sand {
            background-color: #000;
            border: 4px solid #333;
            border-radius: 8px;
            cursor: crosshair;
            image-rendering: pixelated;
            width: 600px;
            height: 600px;
        }

        .controls {
            display: flex;
            gap: 10px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 12px 20px;
            border: none;
            border-radius: 8px;
            cursor: pointer;
            font-weight: bold;
            transition: transform 0.1s, background-color 0.2s, box-shadow 0.2s;
            text-transform: uppercase;
            font-size: 12px;
            letter-spacing: 1px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        button:active {
            transform: translateY(2px);
            box-shadow: 0 2px 3px rgba(0,0,0,0.3);
        }

        .mat-btn {
            color: #fff;
            width: 100px;
        }

        #mat-sand { background-color: var(--sand-color); color: #000; }
        #mat-water { background-color: var(--water-color); }
        #mat-wall { background-color: var(--wall-color); }
        #mat-acid { background-color: var(--acid-color); color: #000; }
        #mat-empty { background-color: var(--empty-color); }

        button.active {
            outline: 3px solid white;
            outline-offset: 2px;
            box-shadow: 0 0 15px rgba(255,255,255,0.4);
        }

        #clear {
            background-color: #cf6679;
            color: white;
            margin-left: 20px;
        }

        .title {
            margin: 0 0 10px 0;
            font-weight: 300;
            letter-spacing: 2px;
            color: var(--accent-color);
        }
    </style>
</head>
<body>

    <div class="container">
        <h1 class="title">SANDBOX</h1>
        <canvas id="sand" width="200" height="200"></canvas>
        <div class="controls">
            <button id="mat-sand" class="mat-btn active">Sand</button>
            <button id="mat-water" class="mat-btn">Water</button>
            <button id="mat-wall" class="mat-btn">Wall</button>
            <button id="mat-acid" class="mat-btn">Acid</button>
            <button id="mat-empty" class="mat-btn">Eraser</button>
            <button id="clear">Clear Grid</button>
        </div>
    </div>

    <script>
        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d', { alpha: false });

        // Simulation Constants
        const W = 100; // Grid width
        const H = 100; // Grid height
        const MATERIALS = {
            empty: { color: '#000000' },
            sand:  { color: '#f4d03f' },
            water: { color: '#3498db' },
            wall:  { color: '#7f8c8d' },
            acid:  { color: '#2ecc71' }
        };

        // State
        let grid = Array(W * H).fill('empty');
        let currentMaterial = 'sand';
        let isMouseDown = false;

        // API Implementation
        window.sim = {
            w: W,
            h: H,
            get: (x, y) => {
                if (x < 0 || x >= W || y < 0 || y >= H) return 'wall';
                return grid[y * W + x];
            },
            set: (x, y, material) => {
                if (x >= 0 && x < W && y >= 0 && y < H) {
                    grid[y * W + x] = material;
                }
            },
            clear: () => {
                grid.fill('empty');
            },
            tick: (n = 1) => {
                for (let step = 0; step < n; step++) {
                    // Process bottom-up to prevent teleporting and ensure stability
                    for (let y = H - 1; y >= 0; y--) {
                        for (let x = 0; x < W; x++) {
                            const idx = y * W + x;
                            const mat = grid[idx];

                            if (mat === 'empty' || mat === 'wall') continue;

                            // SAND logic
                            if (mat === 'sand') {
                                if (y + 1 < H) {
                                    const below = grid[(y + 1) * W + x];
                                    if (below === 'empty' || below === 'water' || below === 'acid') {
                                        // Sink or fall
                                        grid[(y + 1) * W + x] = 'sand';
                                        grid[idx] = below;
                                        continue;
                                    }
                                }
                                // Slide diagonally
                                if (y + 1 < H) {
                                    const dir = Math.random() < 0.5 ? -1 : 1;
                                    const sides = [dir, -dir];
                                    for (let s of sides) {
                                        const nx = x + s;
                                        if (nx >= 0 && nx < W) {
                                            const diag = grid[(y + 1) * W + nx];
                                            if (diag === 'empty' || diag === 'water' || diag === 'acid') {
                                                grid[(y + 1) * W + nx] = 'sand';
                                                grid[idx] = diag;
                                                break;
                                            }
                                        }
                                    }
                                }
                            }

                            // WATER logic
                            else if (mat === 'water') {
                                if (y + 1 < H && grid[(y + 1) * W + x] === 'empty') {
                                    grid[(y + 1) * W + x] = 'water';
                                    grid[idx] = 'empty';
                                } else {
                                    const dir = Math.random() < 0.5 ? -1 : 1;
                                    const sides = [dir, -dir];
                                    for (let s of sides) {
                                        const nx = x + s;
                                        if (nx >= 0 && nx < W && grid[y * W + nx] === 'empty') {
                                            grid[y * W + nx] = 'water';
                                            grid[idx] = 'empty';
                                            break;
                                        }
                                    }
                                }
                            }

                            // ACID logic
                            else if (mat === 'acid') {
                                // Dissolve below
                                if (y + 1 < H) {
                                    const below = grid[(y + 1) * W + x];
                                    if (below === 'sand' || below === 'wall') {
                                        grid[(y + 1) * W + x] = 'empty';
                                        grid[idx] = 'empty'; // Acid is consumed in reaction
                                        continue;
                                    } else if (below === 'empty') {
                                        grid[(y + 1) * W + x] = 'acid';
                                        grid[idx] = 'empty';
                                        continue;
                                    }
                                }
                                // Dissolve or move sideways
                                const dir = Math.random() < 0.5 ? -1 : 1;
                                const sides = [dir, -dir];
                                for (let s of sides) {
                                    const nx = x + s;
                                    if (nx >= 0 && nx < W) {
                                        const sideMat = grid[y * W + nx];
                                        if (sideMat === 'sand' || sideMat === 'wall') {
                                            grid[y * W + nx] = 'empty';
                                            // Acid stays but erodes target
                                            break; 
                                        } else if (sideMat === 'empty') {
                                            grid[y * W + nx] = 'acid';
                                            grid[idx] = 'empty';
                                            break;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        };

        // Rendering
        function render() {
            const imgData = ctx.createImageData(W, H);
            for (let i = 0; i < grid.length; i++) {
                const mat = grid[i];
                const colorHex = MATERIALS[mat].color;
                const r = parseInt(colorHex.slice(1, 3), 16);
                const g = parseInt(colorHex.slice(3, 5), 16);
                const b = parseInt(colorHex.slice(5, 7), 16);

                const px = i * 4;
                imgData.data[px] = r;
                imgData.data[px + 1] = g;
                imgData.data[px + 2] = b;
                imgData.data[px + 3] = 255;
            }
            ctx.putImageData(imgData, 0, 0);
        }

        // Input Handling
        function handleInput(e) {
            const rect = canvas.getBoundingClientRect();
            const scaleX = W / rect.width;
            const scaleY = H / rect.height;
            const x = Math.floor((e.clientX - rect.left) * scaleX);
            const y = Math.floor((e.clientY - rect.top) * scaleY);

            if (x >= 0 && x < W && y >= 0 && y < H) {
                window.sim.set(x, y, currentMaterial);
            }
        }

        canvas.addEventListener('mousedown', (e) => { isMouseDown = true; handleInput(e); });
        window.addEventListener('mouseup', () => { isMouseDown = false; });
        canvas.addEventListener('mousemove', (e) => { if (isMouseDown) handleInput(e); });

        // UI Buttons
        const matButtons = ['mat-sand', 'mat-water', 'mat-wall', 'mat-acid', 'mat-empty'];
        matButtons.forEach(id => {
            document.getElementById(id).addEventListener('click', (e) => {
                currentMaterial = id.replace('mat-', '');
                matButtons.forEach(btnId => document.getElementById(btnId).classList.remove('active'));
                e.target.classList.add('active');
            });
        });

        document.getElementById('clear').addEventListener('click', () => {
            window.sim.clear();
        });

        // Main Loop
        function loop() {
            window.sim.tick(1);
            render();
            requestAnimationFrame(loop);
        }

        loop();
    </script>
</body>
</html>
